// pages/ForgotPasswordForm.tsx
import React, { useState } from 'react';
import {
    Box,
    Paper,
    Typography,
    TextField,
    Button,
    CircularProgress,
    Alert,
    InputAdornment,
} from '@mui/material';
import { Email as EmailIcon, ArrowBack as ArrowBackIcon } from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { request } from '../../../../utils/request';

const ForgotPasswordForm: React.FC = () => {
    const [email, setEmail] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [success, setSuccess] = useState(false);
    const navigate = useNavigate();

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        
        if (!email) {
            setError('Please enter your email address');
            return;
        }

        setLoading(true);
        setError('');

        try {
            const response = await request({
                url: 'auth/forgot-password',
                method: 'post',
                data: { email },
            });

            if (response.status === 'success') {
                setSuccess(true);
            } else {
                setError(response.message || 'Failed to send reset instructions');
            }
        } catch (err: any) {
            setError(err?.message || 'Failed to send reset instructions');
        } finally {
            setLoading(false);
        }
    };

    if (success) {
        return (
            <Box sx={{ 
                minHeight: '100vh', 
                display: 'flex', 
                alignItems: 'center', 
                justifyContent: 'center',
                // background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                p: 2
            }}>
                <Paper elevation={0} sx={{ maxWidth: 450, width: '100%', p: 4, borderRadius: 1, textAlign: 'center' }}>
                    <EmailIcon sx={{ fontSize: 64, color: 'success.main', mb: 2 }} />
                    <Typography variant="h5" fontWeight="bold" sx={{ mb: 2 }}>
                        Check Your Email
                    </Typography>
                    <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
                        We've sent password reset instructions to <strong>{email}</strong>. 
                        Please check your inbox and follow the link to reset your password.
                    </Typography>
                    <Button
                        variant="contained"
                        onClick={() => navigate('/login')}
                        sx={{ textTransform: 'none' }}
                    >
                        Back to Login
                    </Button>
                </Paper>
            </Box>
        );
    }

    return (
        <Box sx={{ 
            minHeight: '100vh', 
            display: 'flex', 
            alignItems: 'center', 
            justifyContent: 'center',
            // background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
            p: 2
        }}>
            <Paper elevation={0} sx={{ maxWidth: 450, width: '100%', p: 4, borderRadius: 1 }}>
                <Box sx={{ textAlign: 'center', mb: 4 }}>
                    <EmailIcon sx={{ fontSize: 48, color: 'primary.main', mb: 2 }} />
                    <Typography variant="h4" fontWeight="bold" sx={{ mb: 1 }}>
                        Forgot Password?
                    </Typography>
                    <Typography variant="body2" color="text.secondary">
                        Enter your email address and we'll send you a link to reset your password
                    </Typography>
                </Box>

                {error && (
                    <Alert severity="error" sx={{ mb: 3 }} onClose={() => setError('')}>
                        {error}
                    </Alert>
                )}

                <form onSubmit={handleSubmit}>
                    <TextField
                        fullWidth
                        size='small'
                        type="email"
                        label="Email Address"
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        disabled={loading}
                        required
                        sx={{ mb: 3 }}
                        InputProps={{
                            startAdornment: (
                                <InputAdornment position="start">
                                    <EmailIcon color="action" />
                                </InputAdornment>
                            ),
                        }}
                    />

                    <Button
                        fullWidth
                        size='small'
                        type="submit"
                        variant="contained"
                        disabled={loading}
                        sx={{ py: 1.2, textTransform: 'none', mb: 2 }}
                    >
                        {loading ? <CircularProgress size={24} /> : 'Send Reset Instructions'}
                    </Button>

                    <Button
                        fullWidth
                        size='small'
                        variant="text"
                        onClick={() => navigate('/login')}
                        disabled={loading}
                        startIcon={<ArrowBackIcon />}
                        sx={{ textTransform: 'none' }}
                    >
                        Back to Login
                    </Button>
                </form>
            </Paper>
        </Box>
    );
};

export default ForgotPasswordForm;